import { VectorStoreIndex, ContextChatEngine } from 'llamaindex';
import { verify } from '@vex/sdk';

// Index federal regulations
const index = await VectorStoreIndex.fromDocuments([
  new Document({ text: 'FOIA 5 U.S.C. § 552(b)...' }),
  new Document({ text: 'Privacy Act requirements...' })
]);

const queryEngine = index.asQueryEngine();

// Vex verification for government queries
const safeQuery = async (question: string) => {
  const response = await queryEngine.query({ question });

  const verified = await verify({
    output: response.response,
    context: response.sourceNodes,
    policy: 'gov-compliance',
    metadata: { agency: 'DOJ', sensitivity: 'public' }
  });

  if (!verified.valid) {
    throw new Error(`Compliance failure: ${verified.reason}`);
  }

  return verified;
};
